#!/usr/bin/env node
/**
 * llms-txt-splitter.js
 *
 * Post-build script that restructures the flat llms.txt generated by
 * @signalwire/docusaurus-plugin-llms-txt into a nested progressive-disclosure
 * layout:
 *
 *   build/llms.txt              — slim root index (<50K) pointing to sections
 *   build/vcluster/llms.txt     — full vCluster link index
 *   build/platform/llms.txt     — full Platform link index
 *
 * Keeps the root under the 50K PASS threshold so it fits within every known
 * agent web-fetch truncation limit. Section files hold the full link lists for
 * agents that follow the root index to the relevant section.
 *
 * Run via npm postbuild (after docusaurus build and all plugin postBuild hooks
 * have finished):
 *   "postbuild": "node plugins/llms-txt-splitter.js"
 *
 * Related: DOC-1319, https://agentdocsspec.com/spec/#llms-txt-size
 */

import { promises as fs } from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const SITE_URL = 'https://vcluster.com';
const BASE_URL = '/docs/';
const OUT_DIR = path.join(path.dirname(fileURLToPath(import.meta.url)), '..', 'build');

async function run() {
  const rootFile = path.join(OUT_DIR, 'llms.txt');

  let raw;
  try {
    raw = await fs.readFile(rootFile, 'utf8');
  } catch {
    console.error('[llms-txt-splitter] build/llms.txt not found — run docusaurus build first');
    process.exit(1);
  }

  const lines = raw.split('\n');

  // Locate the two product section headings produced by @signalwire plugin
  const platformIdx = lines.findIndex((l) => /^### platform\b/i.test(l));
  const vclusterIdx = lines.findIndex((l) => /^### vcluster\b/i.test(l));

  if (platformIdx === -1 || vclusterIdx === -1) {
    console.error(
      '[llms-txt-splitter] Expected ### platform / ### vcluster headings not found in llms.txt',
    );
    process.exit(1);
  }

  // Slice body lines for each section (everything after the heading line)
  const platformBody = lines.slice(platformIdx + 1, vclusterIdx);
  const vclusterBody = lines.slice(vclusterIdx + 1);

  // First non-blank, non-link line is the human-readable section description
  const extractDesc = (bodyLines) =>
    bodyLines.find((l) => l.trim() && !l.trimStart().startsWith('-')) ?? '';

  const platformDesc = extractDesc(platformBody);
  const vclusterDesc = extractDesc(vclusterBody);

  const base = SITE_URL + BASE_URL; // https://vcluster.com/docs/

  // ── build/platform/llms.txt ───────────────────────────────────────────────
  const platformContent =
    `# vCluster Platform Documentation\n\n` +
    `> ${platformDesc}\n\n` +
    `## platform\n` +
    platformBody.join('\n').trimEnd() +
    '\n';

  await fs.mkdir(path.join(OUT_DIR, 'platform'), { recursive: true });
  await fs.writeFile(path.join(OUT_DIR, 'platform', 'llms.txt'), platformContent);

  // ── build/vcluster/llms.txt ───────────────────────────────────────────────
  const vclusterContent =
    `# vCluster Documentation\n\n` +
    `> ${vclusterDesc}\n\n` +
    `## vcluster\n` +
    vclusterBody.join('\n').trimEnd() +
    '\n';

  await fs.mkdir(path.join(OUT_DIR, 'vcluster'), { recursive: true });
  await fs.writeFile(path.join(OUT_DIR, 'vcluster', 'llms.txt'), vclusterContent);

  // ── build/llms.txt (slim root index) ─────────────────────────────────────
  const rootContent =
    `# vCluster Documentation\n\n` +
    `> vCluster is a production-grade Kubernetes platform for AI clouds and enterprises. ` +
    `Provision isolated tenant clusters with hyperscaler-grade reliability. ` +
    `Manage fleets of tenant clusters with vCluster Platform.\n\n` +
    `## vCluster\n\n` +
    `${vclusterDesc}\n\n` +
    `- [vCluster Documentation Index](${base}vcluster/llms.txt): Complete index of vCluster tenant cluster documentation\n` +
    `- [Quick Start](${base}vcluster.md): Choose the right deployment path and get a tenant cluster running in minutes\n\n` +
    `## Platform\n\n` +
    `${platformDesc}\n\n` +
    `- [Platform Documentation Index](${base}platform/llms.txt): Complete index of vCluster Platform documentation\n` +
    `- [What is vCluster Platform?](${base}platform.md): Overview of vCluster Platform\n`;

  await fs.writeFile(rootFile, rootContent);

  // Report sizes and PASS/WARN/FAIL against the 50K/100K spec thresholds
  const status = (n) => (n < 50_000 ? 'PASS' : n < 100_000 ? 'WARN' : 'FAIL');
  const sizes = {
    root: rootContent.length,
    platform: platformContent.length,
    vcluster: vclusterContent.length,
  };

  console.log('[llms-txt-splitter] Split complete:');
  console.log(`  root:     ${sizes.root.toLocaleString()} chars  (${status(sizes.root)})`);
  console.log(`  platform: ${sizes.platform.toLocaleString()} chars (${status(sizes.platform)})`);
  console.log(`  vcluster: ${sizes.vcluster.toLocaleString()} chars (${status(sizes.vcluster)})`);
}

run().catch((err) => {
  console.error('[llms-txt-splitter] Fatal error:', err);
  process.exit(1);
});
